--
-- Table structure for table `admin_operation_logs`
--

DROP TABLE IF EXISTS `admin_operation_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `admin_operation_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `admin_user_id` int DEFAULT NULL COMMENT '账号被删后仍保留日志',
  `admin_username` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '冗余存储，确保日志可追溯',
  `module` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '操作模块，如：人格管理/Prompt管理/用户管理',
  `action` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '操作类型：create/edit/delete/view/publish/rollback/login/logout/unlock',
  `target_description` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '操作对象描述',
  `before_value` text COLLATE utf8mb4_unicode_ci COMMENT '修改前内容',
  `after_value` text COLLATE utf8mb4_unicode_ci COMMENT '修改后内容',
  `ip_address` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=75 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

