DROP TABLE IF EXISTS `admin_users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `admin_users` (
  `id` int NOT NULL AUTO_INCREMENT,
  `username` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `password_hash` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `role` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '角色：super_admin/ops_admin/ai_trainer/tech_ops',
  `remark` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注说明',
  `is_active` tinyint(1) NOT NULL,
  `is_locked` tinyint(1) NOT NULL COMMENT 'True=账号已锁定，需超级管理员手动解锁',
  `login_fail_count` int NOT NULL,
  `last_login_at` datetime DEFAULT NULL,
  `last_password_change_at` datetime DEFAULT NULL,
  `created_at` datetime NOT NULL,
  `created_by` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '创建者账号名',
  PRIMARY KEY (`id`),
  UNIQUE KEY `ix_admin_users_username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

