DROP TABLE IF EXISTS `emotion_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `emotion_log` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `emotion_label` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `confidence` float NOT NULL,
  `conversation_id` int NOT NULL,
  `created_at` datetime NOT NULL,
  `round_id` varchar(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'TD-016：与本轮 conversation_log 相同 round_id',
  PRIMARY KEY (`id`),
  KEY `ix_emotion_log_user_id` (`user_id`),
  KEY `ix_emotion_log_conversation_id` (`conversation_id`),
  CONSTRAINT `emotion_log_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `emotion_log_ibfk_2` FOREIGN KEY (`conversation_id`) REFERENCES `conversation_log` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=212 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

